parameters.jsCode:
// Search the T-0 Companies database by company name
const NOTION_TOKEN = 'REDACTED_NOTION_TOKEN';
const DB_ID = '330c0fdf-942d-8156-a493-c853230724d6';

const searchName = query.trim();
if (!searchName) return 'No search term provided';

// Build search variants: full name, first word (if multi-word), without common suffixes
const variants = [searchName];
const words = searchName.split(/\s+/);
if (words.length > 1) {
  variants.push(words[0]); // First word only (e.g., "Lucid" from "Lucid Software")
}
// Remove common suffixes
const stripped = searchName.replace(/\s+(Inc\.?|Corp\.?|Ltd\.?|GmbH|AG|LLC|Software|Digital|Labs?|AI|Technologies|Systems)$/i, '').trim();
if (stripped && stripped !== searchName) {
  variants.push(stripped);
}

// Deduplicate variants
const uniqueVariants = [...new Set(variants.map(v => v.toLowerCase()))];
const allResults = new Map();

for (const variant of uniqueVariants) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://api.notion.com/v1/databases/${DB_ID}/query`,
      headers: {
        'Authorization': `Bearer ${NOTION_TOKEN}`,
        'Content-Type': 'application/json',
        'Notion-Version': '2022-06-28'
      },
      body: {
        filter: {
          property: 'Name',
          title: { contains: variant }
        },
        page_size: 5
      },
      json: true
    });

    for (const r of (response.results || [])) {
      if (!allResults.has(r.id)) {
        allResults.set(r.id, {
          id: r.id,
          name: (r.properties.Name?.title || []).map(t => t.plain_text).join(''),
          type: r.properties.Type?.select?.name || '',
          relevance: r.properties.Relevance?.select?.name || '',
          status: r.properties.Status?.select?.name || '',
          mention_count: r.properties['Mention Count']?.number || 0
        });
      }
    }
  } catch (e) {
    // Continue with other variants
  }
}

if (allResults.size === 0) {
  return `No companies found matching "${searchName}" (searched variants: ${uniqueVariants.join(', ')})`;
}
return JSON.stringify([...allResults.values()], null, 2);

// Create a new company in the T-0 Companies database
const NOTION_TOKEN = 'REDACTED_NOTION_TOKEN';
const DB_ID = '330c0fdf-942d-8156-a493-c853230724d6';

let input;
try {
  input = typeof query === 'string' ? JSON.parse(query) : query;
} catch(e) {
  return 'Error: Input must be valid JSON with fields: name, type, focus, description, relevance, country, url';
}

const name = input.name;
if (!name) return 'Error: company name is required';

const today = new Date().toISOString().split('T')[0];

const properties = {
  'Name': { title: [{ text: { content: name } }] },
  'Status': { select: { name: 'Active' } },
  'First Seen': { date: { start: today } },
  'Last Mentioned': { date: { start: today } },
  'Mention Count': { number: 1 }
};

if (input.type) properties['Type'] = { select: { name: input.type } };
if (input.relevance) properties['Relevance'] = { select: { name: input.relevance } };
if (input.country) properties['Country'] = { select: { name: input.country } };
if (input.url) properties['URL'] = { url: input.url };
if (input.description) properties['Description'] = { rich_text: [{ text: { content: input.description.substring(0, 2000) } }] };
if (input.focus && Array.isArray(input.focus)) {
  properties['Focus'] = { multi_select: input.focus.map(f => ({ name: f })) };
}

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.notion.com/v1/pages',
    headers: {
      'Authorization': `Bearer ${NOTION_TOKEN}`,
      'Content-Type': 'application/json',
      'Notion-Version': '2022-06-28'
    },
    body: { parent: { database_id: DB_ID }, properties },
    json: true
  });

  if (response.id) {
    return JSON.stringify({ success: true, id: response.id, name: name });
  } else {
    return `Error creating company: ${JSON.stringify(response)}`;
  }
} catch (e) {
  return `Error creating company: ${e.message}`;
}

// Collect Intelligence Agent results and merge with original article data
const agentItems = $input.all();
const originalItems = $('Split to Items').all();

const output = [];

for (let i = 0; i < agentItems.length; i++) {
  const agentData = agentItems[i].json;
  const original = originalItems[i]?.json || {};

  // Parse the agent's JSON output
  const agentOutput = agentData.output || '{}';
  let parsed = {};
  try {
    // Clean potential markdown wrapping
    let cleaned = agentOutput.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    // Find the JSON object — look for the companies key specifically
    const jsonMatch = cleaned.match(/\{[\s\S]*"companies"[\s\S]*\}/);
    if (jsonMatch) {
      parsed = JSON.parse(jsonMatch[0]);
    } else {
      // Fallback: try the whole thing
      const anyJson = cleaned.match(/\{[\s\S]*\}/);
      if (anyJson) parsed = JSON.parse(anyJson[0]);
    }
  } catch(e) {
    parsed = { companies: [], enriched_tags: [] };
  }

  // Extract company IDs for the Notes relation — validate they look like UUIDs
  const uuidPattern = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/;
  const companyIds = (parsed.companies || [])
    .filter(c => c.id && typeof c.id === 'string' && uuidPattern.test(c.id))
    .map(c => ({ id: c.id }));

  output.push({
    json: {
      title: original.title,
      url: original.url,
      summary: original.summary,
      source_name: original.source_name,
      source_page_id: original.source_page_id,
      published: original.published,
      full_text: original.full_text,
      relevance_score: original.relevance_score,
      triage_category_tags: original.triage_category_tags,
      triage_ai_tags: original.triage_ai_tags,
      triage_summary: original.triage_summary,
      origin_description: original.origin_description,
      source_category_tags: original.source_category_tags,
      company_ids: companyIds,
      enriched_tags: parsed.enriched_tags || [],
      companies_found: (parsed.companies || []).length,
      sources_processed: original.sources_processed,
    }
  });
}

return output;

// Update an existing company's Last Mentioned date and increment Mention Count
const NOTION_TOKEN = 'REDACTED_NOTION_TOKEN';

let input;
try {
  input = typeof query === 'string' ? JSON.parse(query) : query;
} catch(e) {
  return 'Error: Input must be valid JSON with field: id (the company page ID)';
}

const pageId = input.id;
if (!pageId) return 'Error: company page id is required';

const currentCount = input.current_mention_count || 0;
const today = new Date().toISOString().split('T')[0];

try {
  const response = await this.helpers.httpRequest({
    method: 'PATCH',
    url: `https://api.notion.com/v1/pages/${pageId}`,
    headers: {
      'Authorization': `Bearer ${NOTION_TOKEN}`,
      'Content-Type': 'application/json',
      'Notion-Version': '2022-06-28'
    },
    body: {
      properties: {
        'Last Mentioned': { date: { start: today } },
        'Mention Count': { number: currentCount + 1 }
      }
    },
    json: true
  });

  if (response.id) {
    return JSON.stringify({ success: true, id: response.id, new_count: currentCount + 1 });
  } else {
    return `Error updating company: ${JSON.stringify(response)}`;
  }
} catch (e) {
  return `Error updating company: ${e.message}`;
}
